@(content: String)(implicit messages: Messages)

import play.api.mvc.AnyContent
import play.twirl.api.Html

def sanitizeHtml(input: String): Html = {
  val allowedTags = Set("a", "b", "i", "u", "img")
  val allowedAttributes = Map(
    "a" -> Set("href"),
    "img" -> Set("src", "alt")
  )
  
  def isSafeTag(tag: String): Boolean = allowedTags.contains(tag)
  
  def isSafeAttribute(tag: String, attr: String): Boolean = 
    allowedAttributes.get(tag).map(_.contains(attr)).getOrElse(false)
  
  val regex = """<([a-zA-Z0-9]+)([^>]*)>""".r
  val sanitizedContent = regex.replaceAllIn(content) { matchData =>
    val tag = matchData.group(1)
    if (isSafeTag(tag)) {
      val attributes = matchData.group(2).split(" ")
        .map(_.trim)
        .filter(attr => isSafeAttribute(tag, attr.split("=")(0)))
        .mkString(" ")
      s"<$tag $attributes>"
    } else {
      ""
    }
  }
  
  Html(sanitizedContent)
}

<div class="post">
  @sanitizeHtml(content)
</div>